#include <stdio.h>
#include <math.h>
#define MAXN 2000
#define EPS 1e-6
int T, N;
int x[MAXN], y[MAXN];
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &x[i], &y[i]);
        }
        double min_sum = 1e18;
        double min_x, min_y;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                double sum = 0;
                double cx = (x[i] + x[j]) / 2.0;
                double cy = (y[i] + y[j]) / 2.0;
                for (int k = 0; k < N; k++) {
                    sum += sqrt((cx - x[k]) * (cx - x[k]) + (cy - y[k]) * (cy - y[k]));
                }
                if (sum < min_sum) {
                    min_sum = sum;
                    min_x = cx;
                    min_y = cy;
                }
            }
        }
        printf("%.6f\n", min_sum);
    }
    return 0;
}

