        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] x = new int[N];
            int[] y = new int[N];
            for (int i = 0; i < N; i++) {
                x[i] = sc.nextInt();
                y[i] = sc.nextInt();
            }
            double min_sum = 1e18;
            double min_x = 0, min_y = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    double sum = 0;
                    double cx = (x[i] + x[j]) / 2.0;
                    double cy = (y[i] + y[j]) / 2.0;
                    for (int k = 0; k < N; k++) {
                        sum += Math.sqrt((cx - x[k]) * (cx - x[k]) + (cy - y[k]) * (cy - y[k]));
                    }
                    if (sum < min_sum) {
                        min_sum = sum;
                        min_x = cx;
                        min_y = cy;
                    }
                }
            }
            System.out.printf("%.6f\n", min_sum);
